import axiosInstance from '../../../api/axiosInstance';

export const getBookmarks = () =>
  axiosInstance.get('/bookmarks');

export const createBookmark = (data) =>
  axiosInstance.post('/bookmarks', data);

export const updateBookmark = (bookmarkId, data) =>
  axiosInstance.put(`/bookmarks/${bookmarkId}`, data);

export const deleteBookmark = (bookmarkId) =>
  axiosInstance.delete(`/bookmarks/${bookmarkId}`);

export const getAiSummaryForFestival = (festivalId) =>
  axiosInstance.get(`/bookmarks/ai-summary/${festivalId}`);
