import { useState } from 'react';
import Header from '../../components/Header';
import {
  FestivalSearchBar,
  FestivalGrid,
  searchFestivals,
} from '../../features/festivals';
import { PageWrapper, PageInner, PageTitle } from './MainPage.styles';

const MOCK_FESTIVALS = [
  {
    id: '1',
    title: '서울 봄꽃 축제',
    location: '서울특별시 강남구',
    startDate: '2026-04-01',
    endDate: '2026-04-15',
    imageUrl: '',
  },
  {
    id: '2',
    title: '부산 해운대 모래축제',
    location: '부산광역시 해운대구',
    startDate: '2026-05-10',
    endDate: '2026-05-20',
    imageUrl: '',
  },
  {
    id: '3',
    title: '제주 유채꽃 축제',
    location: '제주특별자치도 서귀포시',
    startDate: '2026-03-20',
    endDate: '2026-04-10',
    imageUrl: '',
  },
];

const MainPage = () => {
  const [festivals, setFestivals] = useState([]);
  const [loading, setLoading] = useState(false);
  const [searched, setSearched] = useState(false);

  const handleSearch = async (params) => {
    setLoading(true);
    setSearched(true);
    try {
      const { data } = await searchFestivals(params);
      setFestivals(data.festivals || data);
    } catch {
      setFestivals(MOCK_FESTIVALS);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Header />
      <PageWrapper>
        <PageInner>
          <PageTitle>지역별 축제 검색</PageTitle>
          <FestivalSearchBar onSearch={handleSearch} />
          <FestivalGrid
            festivals={searched ? festivals : []}
            loading={loading}
          />
        </PageInner>
      </PageWrapper>
    </>
  );
};

export default MainPage;
