import { StyledButton } from './Button.styles';

const Button = ({
  children,
  variant = 'primary',
  size = 'md',
  pill = false,
  fullWidth = false,
  type = 'button',
  onClick,
  disabled = false,
  ...rest
}) => (
  <StyledButton
    type={type}
    $variant={variant}
    $size={size}
    $pill={pill}
    $fullWidth={fullWidth}
    onClick={onClick}
    disabled={disabled}
    {...rest}
  >
    {children}
  </StyledButton>
);

export default Button;
