import axiosInstance from '../../../api/axiosInstance';

export const searchFestivals = ({ areaCode, sigunguCode, keyword }) =>
  axiosInstance.get('/festivals', {
    params: { areaCode, sigunguCode, keyword },
  });

export const getFestivalDetail = (festivalId) =>
  axiosInstance.get(`/festivals/${festivalId}`);

export const getAiSummary = (festivalId) =>
  axiosInstance.get(`/festivals/${festivalId}/ai-summary`);
