import styled from 'styled-components';

export const StyledButton = styled.button`
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: ${({ $size }) => ($size === 'sm' ? '0.5rem 1rem' : '0.75rem 2rem')};
  font-size: ${({ theme, $size }) =>
    $size === 'sm' ? theme.fontSizes.sm : theme.fontSizes.md};
  font-weight: 600;
  border-radius: ${({ $pill, theme }) =>
    $pill ? theme.borderRadius.pill : theme.borderRadius.md};
  background-color: ${({ theme, $variant }) => {
    switch ($variant) {
      case 'mint':
        return theme.colors.edit;
      case 'danger':
        return theme.colors.danger;
      case 'outline':
        return 'transparent';
      default:
        return theme.colors.primary;
    }
  }};
  color: ${({ theme, $variant }) =>
    $variant === 'outline' ? theme.colors.primary : theme.colors.white};
  border: ${({ theme, $variant }) =>
    $variant === 'outline' ? `2px solid ${theme.colors.primary}` : 'none'};
  transition: all 0.2s ease;
  min-width: ${({ $fullWidth }) => ($fullWidth ? '100%' : 'auto')};

  &:hover {
    opacity: 0.9;
    transform: translateY(-1px);
  }

  &:active {
    transform: translateY(0);
  }

  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;
