import { useState } from 'react';
import MemoTextarea from './MemoTextarea';
import { updateBookmark, deleteBookmark } from '../api/bookmarksApi';
import {
  Card,
  CardImage,
  CardBody,
  CardTitle,
  CardMeta,
  CardActions,
  EditButton,
  DeleteButton,
} from './BookmarkCard.styles';

const BookmarkCard = ({ bookmark, onUpdate, onDelete }) => {
  const [memo, setMemo] = useState(bookmark.memo || '');
  const [saving, setSaving] = useState(false);

  const handleEdit = async () => {
    setSaving(true);
    try {
      await updateBookmark(bookmark.id, { memo });
      onUpdate?.(bookmark.id, { memo });
    } catch (err) {
      console.error('메모 수정 실패:', err);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!window.confirm('이 축제를 찜 목록에서 삭제하시겠습니까?')) return;
    try {
      await deleteBookmark(bookmark.id);
      onDelete?.(bookmark.id);
    } catch (err) {
      console.error('삭제 실패:', err);
    }
  };

  const { festival } = bookmark;

  return (
    <Card>
      <CardImage $imageUrl={festival?.imageUrl} />
      <CardBody>
        <CardTitle>{festival?.title || '축제명'}</CardTitle>
        <CardMeta>{festival?.location}</CardMeta>
        <MemoTextarea value={memo} onChange={(e) => setMemo(e.target.value)} />
        <CardActions>
          <EditButton onClick={handleEdit} disabled={saving}>
            {saving ? '저장 중...' : '수정'}
          </EditButton>
          <DeleteButton onClick={handleDelete}>삭제</DeleteButton>
        </CardActions>
      </CardBody>
    </Card>
  );
};

export default BookmarkCard;
