import { useState } from 'react';
import { BookmarkBtn } from './BookmarkButton.styles';
import { createBookmark } from '../api/bookmarksApi';

const BookmarkButton = ({ festivalId, aiSummary, onBookmarked }) => {
  const [active, setActive] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleClick = async () => {
    if (active || loading) return;
    setLoading(true);
    try {
      await createBookmark({
        festivalId,
        aiSummary,
        memo: '',
      });
      setActive(true);
      onBookmarked?.();
    } catch (err) {
      console.error('찜하기 실패:', err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <BookmarkBtn $active={active} onClick={handleClick} disabled={loading || active}>
      {loading ? '저장 중...' : active ? '♥ 찜 완료' : '♡ 찜하기'}
    </BookmarkBtn>
  );
};

export default BookmarkButton;
