import { Link, useNavigate } from 'react-router-dom';
import useAuth from '../../hooks/useAuth';
import {
  HeaderContainer,
  HeaderInner,
  Logo,
  Nav,
  NavLink,
} from './Header.styles';

const Header = () => {
  const { isAuthenticated, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <HeaderContainer>
      <HeaderInner>
        <Logo as={Link} to="/">
          FestAI
        </Logo>
        <Nav>
          {isAuthenticated ? (
            <>
              <NavLink as={Link} to="/">
                축제 검색
              </NavLink>
              <NavLink as={Link} to="/mypage">
                마이페이지
              </NavLink>
              <NavLink as="button" onClick={handleLogout} style={{ background: 'none', border: 'none', cursor: 'pointer' }}>
                로그아웃
              </NavLink>
            </>
          ) : (
            <NavLink as={Link} to="/login">
              로그인
            </NavLink>
          )}
        </Nav>
      </HeaderInner>
    </HeaderContainer>
  );
};

export default Header;
