import {
  InputWrapper,
  Label,
  StyledInput,
  StyledTextarea,
} from './Input.styles';

export const Input = ({
  label,
  type = 'text',
  placeholder,
  value,
  onChange,
  name,
  id,
  ...rest
}) => (
  <InputWrapper>
    {label && <Label htmlFor={id || name}>{label}</Label>}
    <StyledInput
      id={id || name}
      type={type}
      name={name}
      placeholder={placeholder}
      value={value}
      onChange={onChange}
      {...rest}
    />
  </InputWrapper>
);

export const Textarea = ({
  label,
  placeholder,
  value,
  onChange,
  name,
  id,
  rows = 3,
  ...rest
}) => (
  <InputWrapper>
    {label && <Label htmlFor={id || name}>{label}</Label>}
    <StyledTextarea
      id={id || name}
      name={name}
      placeholder={placeholder}
      value={value}
      onChange={onChange}
      rows={rows}
      {...rest}
    />
  </InputWrapper>
);

export default Input;
