import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import Header from '../../components/Header';
import {
  FestivalDetailInfo,
  getFestivalDetail,
} from '../../features/festivals';
import {
  AiSummaryBox,
  BookmarkButton,
  getAiSummaryForFestival,
} from '../../features/bookmarks';
import {
  PageWrapper,
  PageInner,
  DetailLayout,
  LeftColumn,
  RightColumn,
  BookmarkSection,
} from './DetailPage.styles';

const MOCK_FESTIVAL = {
  id: '1',
  title: '서울 봄꽃 축제',
  location: '서울특별시 강남구',
  startDate: '2026-04-01',
  endDate: '2026-04-15',
  description:
    '가족과 함께 즐기기 좋은 서울 봄꽃 축제입니다.\n유모차 동선이 잘 정비되어 있으며, 다양한 체험 프로그램이 마련되어 있습니다.',
  imageUrl: '',
};

const DetailPage = () => {
  const { festivalId } = useParams();
  const [festival, setFestival] = useState(null);
  const [aiSummary, setAiSummary] = useState([]);
  const [summaryLoading, setSummaryLoading] = useState(true);

  useEffect(() => {
    const fetchDetail = async () => {
      try {
        const { data } = await getFestivalDetail(festivalId);
        setFestival(data);
      } catch {
        setFestival({ ...MOCK_FESTIVAL, id: festivalId });
      }
    };

    const fetchSummary = async () => {
      setSummaryLoading(true);
      try {
        const { data } = await getAiSummaryForFestival(festivalId);
        setAiSummary(data.summary || data);
      } catch {
        setAiSummary([]);
      } finally {
        setSummaryLoading(false);
      }
    };

    fetchDetail();
    fetchSummary();
  }, [festivalId]);

  return (
    <>
      <Header />
      <PageWrapper>
        <PageInner>
          <DetailLayout>
            <LeftColumn>
              <FestivalDetailInfo festival={festival} />
            </LeftColumn>
            <RightColumn>
              <AiSummaryBox summary={aiSummary} loading={summaryLoading} />
              <BookmarkSection>
                <BookmarkButton
                  festivalId={festivalId}
                  aiSummary={aiSummary}
                />
              </BookmarkSection>
            </RightColumn>
          </DetailLayout>
        </PageInner>
      </PageWrapper>
    </>
  );
};

export default DetailPage;
