import {
  DetailImage,
  DetailTitle,
  DetailDescription,
  DetailMeta,
} from './FestivalDetailInfo.styles';

const FestivalDetailInfo = ({ festival }) => {
  if (!festival) return null;

  const { title, location, startDate, endDate, description, imageUrl } = festival;

  return (
    <div>
      <DetailImage $imageUrl={imageUrl}>
        {!imageUrl && '대표 이미지'}
      </DetailImage>
      <DetailTitle>{title}</DetailTitle>
      <DetailMeta>{location}</DetailMeta>
      <DetailMeta>
        {startDate} ~ {endDate}
      </DetailMeta>
      <DetailDescription>{description || '상세 소개글이 없습니다.'}</DetailDescription>
    </div>
  );
};

export default FestivalDetailInfo;
