import { useEffect, useState } from 'react';
import Header from '../../components/Header';
import { BookmarkCard, getBookmarks } from '../../features/bookmarks';
import {
  PageWrapper,
  PageInner,
  PageTitle,
  BookmarkGrid,
  EmptyMessage,
} from './MyPage.styles';

const MOCK_BOOKMARKS = [
  {
    id: '1',
    memo: '아이들과 함께 가기 좋아요!',
    festival: {
      title: '서울 봄꽃 축제',
      location: '서울특별시 강남구',
      imageUrl: '',
    },
  },
  {
    id: '2',
    memo: '주차장 미리 확인 필요',
    festival: {
      title: '부산 해운대 모래축제',
      location: '부산광역시 해운대구',
      imageUrl: '',
    },
  },
];

const MyPage = () => {
  const [bookmarks, setBookmarks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchBookmarks = async () => {
      try {
        const { data } = await getBookmarks();
        setBookmarks(data.bookmarks || data);
      } catch {
        setBookmarks(MOCK_BOOKMARKS);
      } finally {
        setLoading(false);
      }
    };
    fetchBookmarks();
  }, []);

  const handleUpdate = (id, updates) => {
    setBookmarks((prev) =>
      prev.map((b) => (b.id === id ? { ...b, ...updates } : b)),
    );
  };

  const handleDelete = (id) => {
    setBookmarks((prev) => prev.filter((b) => b.id !== id));
  };

  return (
    <>
      <Header />
      <PageWrapper>
        <PageInner>
          <PageTitle>내가 찜한 축제</PageTitle>
          {loading ? (
            <EmptyMessage>불러오는 중...</EmptyMessage>
          ) : bookmarks.length === 0 ? (
            <EmptyMessage>아직 찜한 축제가 없습니다.</EmptyMessage>
          ) : (
            <BookmarkGrid>
              {bookmarks.map((bookmark) => (
                <BookmarkCard
                  key={bookmark.id}
                  bookmark={bookmark}
                  onUpdate={handleUpdate}
                  onDelete={handleDelete}
                />
              ))}
            </BookmarkGrid>
          )}
        </PageInner>
      </PageWrapper>
    </>
  );
};

export default MyPage;
